defaults
auth           on
tls            on
tls_starttls   on
logfile        /var/log/msmtp.log

account        default
host           {{ vault_smtp_host }}
port           587
from           {{ notify_email_from }}
user           {{ vault_smtp_user }}
password       {{ vault_smtp_password }}

#!/bin/bash
set -euo pipefail

while [[ $# -gt 0 ]]; do
    case "$1" in
        --job)    JOB="$2"; shift 2 ;;
        --run)    RUN="$2"; shift 2 ;;
        --result) RESULT="$2"; shift 2 ;;
        --to)     TO="$2"; shift 2 ;;
        *)        echo "Unknown argument: $1" >&2; exit 1 ;;
    esac
done

SUBJECT="[Dropkick CI] $JOB #$RUN: $RESULT"
LINK="http://localhost:8080/jobs/$JOB/$RUN"

msmtp -t <<EOF
To: $TO
From: ${DROPKICK_FROM:-ci@dropkick.local}
Subject: $SUBJECT

Job:    $JOB
Run:    #$RUN
Result: $RESULT

Details: $LINK
EOF

LAMINAR_BIND_HTTP={{ laminar_bind_http }}
LAMINAR_BIND_RPC={{ laminar_bind_rpc }}
LAMINAR_TITLE={{ laminar_title }}
LAMINAR_KEEP_RUNDIRS={{ laminar_keep_rundirs }}

#!/bin/bash
set -euo pipefail

WORKSPACE="/var/lib/laminar/run/{{ item.name }}/workspace"

# Ensure workspace exists
if [ ! -d "$WORKSPACE/.git" ]; then
    git clone "{{ item.url }}" "$WORKSPACE"
fi

cd "$WORKSPACE"
git fetch origin
git checkout "origin/{{ item.branch }}" --force
git clean -fdx

# Run the build command
{% if item.timeout is defined %}
timeout {{ item.timeout }} {{ item.command }}
{% else %}
{{ item.command }}
{% endif %}

/var/log/dropkick/*.log {
    daily
    rotate 14
    compress
    delaycompress
    missingok
    notifempty
    create 0644 {{ dropkick_user }} {{ dropkick_user }}
}

